import{_ as i,c as s,o as a,a2 as o}from"./chunks/framework.CIiVzG-O.js";const d=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1784654795000}'),t={name:"guide/troubleshooting.md"};function r(n,e,l,p,h,c){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>This page collects common problems for NueZip on macOS and how to resolve them.</p><h2 id="application-won-t-start-or-crashes-on-launch" tabindex="-1">Application won&#39;t start or crashes on launch <a class="header-anchor" href="#application-won-t-start-or-crashes-on-launch" aria-label="Permalink to &quot;Application won&#39;t start or crashes on launch&quot;">​</a></h2><p>Symptoms: NueZip does not open, crashes immediately, or shows an unexpected error.</p><p>Steps to try:</p><ol><li>Ensure your macOS version meets the minimum requirements (macOS 14 Sonoma+).</li><li>Quit and relaunch the app.</li><li>Reboot your Mac.</li><li>If the app was downloaded from GitHub Releases, try downloading the latest build or the notarized version.</li><li>If problems persist, collect logs (see below) and open an issue.</li></ol><h2 id="cannot-open-a-rar-archive" tabindex="-1">Cannot open a RAR archive <a class="header-anchor" href="#cannot-open-a-rar-archive" aria-label="Permalink to &quot;Cannot open a RAR archive&quot;">​</a></h2><p>Symptoms: NueZip fails to open a <code>.rar</code> file, or shows an error.</p><p>Checklist:</p><ol><li>Ensure the RAR file is not corrupted. Try opening it with another tool like The Unarchiver.</li><li>Multi-volume RAR archives must have all parts present (<code>.part1.rar</code>, <code>.part2.rar</code>, etc.).</li><li>Password-protected RAR archives require the correct password.</li><li>RAR5 format is supported. If you have an older RAR format, please report it.</li></ol><h2 id="extraction-fails-with-password-error" tabindex="-1">Extraction fails with password error <a class="header-anchor" href="#extraction-fails-with-password-error" aria-label="Permalink to &quot;Extraction fails with password error&quot;">​</a></h2><p>Symptoms: Extraction fails with &quot;Wrong password&quot; or decryption error.</p><p>Checklist:</p><ol><li>Verify the password is correct — passwords are case-sensitive.</li><li>Ensure the correct encryption type is supported (AES-256 for ZIP).</li><li>Try re-entering the password from the password manager.</li></ol><h2 id="finder-extension-not-showing" tabindex="-1">Finder Extension not showing <a class="header-anchor" href="#finder-extension-not-showing" aria-label="Permalink to &quot;Finder Extension not showing&quot;">​</a></h2><p>Symptoms: Right-clicking an archive in Finder shows no NueZip options.</p><p>Checklist:</p><ol><li>Enable the extension: System Settings → Privacy &amp; Security → Extensions → Finder Extensions → Enable <strong>NueZip</strong>.</li><li>Restart Finder: Right-click Finder in Activity Monitor → Relaunch, or run <code>killall Finder</code> in Terminal.</li><li>Reinstall the app if the extension still doesn&#39;t appear.</li></ol><h2 id="license-purchase-not-showing" tabindex="-1">License / purchase not showing <a class="header-anchor" href="#license-purchase-not-showing" aria-label="Permalink to &quot;License / purchase not showing&quot;">​</a></h2><p>Symptoms: You purchased NueZip but it still shows as trial.</p><p>Checklist:</p><ol><li>Ensure you are signed in to the same Apple ID used for the purchase.</li><li>Restore purchases: NueZip → Settings → License → Restore Purchases.</li><li>Contact support if the issue persists.</li></ol><h2 id="how-to-collect-debug-logs" tabindex="-1">How to collect debug logs <a class="header-anchor" href="#how-to-collect-debug-logs" aria-label="Permalink to &quot;How to collect debug logs&quot;">​</a></h2><p>To help diagnose issues, collect debug logs from NueZip:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Copy logs to Desktop for sharing</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Containers/com.w3cub.nuezip/Data/Library/Logs/NueZip/nuezip.log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Desktop/NueZip-Logs</span></span></code></pre></div><p>Then open an issue on <a href="https://github.com/nuezip/nuezip/issues" target="_blank" rel="noreferrer">GitHub Issues</a> and attach the logs.</p><h2 id="permission-related-issues" tabindex="-1">Permission-related issues <a class="header-anchor" href="#permission-related-issues" aria-label="Permalink to &quot;Permission-related issues&quot;">​</a></h2><p>If a feature prompts for permission but doesn&#39;t work after granting it:</p><ol><li>Quit the app and reopen it after granting the permission.</li><li>If needed, reset the permission prompt with <code>tccutil</code> (see the <a href="./permissions.html">Permissions guide</a>).</li></ol><h2 id="performance-issues" tabindex="-1">Performance issues <a class="header-anchor" href="#performance-issues" aria-label="Permalink to &quot;Performance issues&quot;">​</a></h2><p>If the app is slow or unresponsive:</p><ol><li>Close other heavy applications.</li><li>Try extracting a smaller archive to isolate the issue.</li><li>Restart the app if performance degrades over time.</li></ol><h2 id="view-logs" tabindex="-1">View logs <a class="header-anchor" href="#view-logs" aria-label="Permalink to &quot;View logs&quot;">​</a></h2><p>To troubleshoot crashes or issues, application logs are the most useful artifact. In sandboxed (App Store) builds, check:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Containers/com.w3cub.nuezip/Data/Library/Logs/NueZip/nuezip.log</span></span></code></pre></div><h2 id="resetting-the-app" tabindex="-1">Resetting the app <a class="header-anchor" href="#resetting-the-app" aria-label="Permalink to &quot;Resetting the app&quot;">​</a></h2><p>To reset settings and clear local data:</p><ol><li>Quit NueZip</li><li>Remove the container (be careful—this deletes all settings):</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Containers/com.w3cub.nuezip</span></span></code></pre></div><ol start="3"><li>Reopen NueZip and reconfigure.</li></ol><h2 id="report-an-issue" tabindex="-1">Report an issue <a class="header-anchor" href="#report-an-issue" aria-label="Permalink to &quot;Report an issue&quot;">​</a></h2><p>When opening an issue, include:</p><ul><li>macOS version (Apple menu → About This Mac)</li><li>NueZip version (NueZip → About)</li><li>Steps to reproduce</li><li>Logs (see <a href="#view-logs">View logs</a> section for how to collect them)</li></ul><p>This helps maintainers identify and fix the problem faster.</p>`,44)])])}const g=i(t,[["render",r]]);export{d as __pageData,g as default};
